91	describe('rate limiter', () => {
92	  const limiterApp = express();
93	  limiterApp.use(express.json());
94	  limiterApp.use(cors({ origin: ['http://localhost:5173'], methods: ['GET', 'POST'], allowedHeaders: ['Authorization', 'Content-Type'] }));
95	  limiterApp.use('/api/fibaro', createRequireAuth(API_TOKEN));
96	  limiterApp.use('/api/fibaro', rateLimit({ max: 2, windowMs: 60000, standardHeaders: true, legacyHeaders: false, message: { error: 'Too many requests' } }));
97	  limiterApp.use('/api/fibaro', fibaroRouter);
98	
99	  beforeEach(() => {
100	    mockGet.mockReset();
101	    mockGet.mockResolvedValue({ data: [] });
102	    invalidateCache('/api/devices');
103	  });
104	
105	  it('returns 429 after exceeding the limit', async () => {
106	    await request(limiterApp).get('/api/fibaro/devices').set(AUTH);
107	    await request(limiterApp).get('/api/fibaro/devices').set(AUTH);
108	    const res = await request(limiterApp).get('/api/fibaro/devices').set(AUTH);
109	    expect(res.status).toBe(429);
110	    expect(res.body).toEqual({ error: 'Too many requests' });
111	  });
112	
113	  it('unauthenticated requests do not count against the rate limit budget', async () => {
114	    // Use a fresh app with its own rate limiter instance so prior tests don't affect the budget
115	    const freshApp = express();
116	    freshApp.use(express.json());
117	    freshApp.use('/api/fibaro', createRequireAuth(API_TOKEN));
118	    freshApp.use('/api/fibaro', rateLimit({ max: 2, windowMs: 60000, standardHeaders: true, legacyHeaders: false, message: { error: 'Too many requests' } }));
119	    freshApp.use('/api/fibaro', fibaroRouter);
120	
121	    // Send 2 unauthenticated requests (401, should not consume budget)
122	    await request(freshApp).get('/api/fibaro/devices'); // 401, no budget consumed
123	    await request(freshApp).get('/api/fibaro/devices'); // 401, no budget consumed
124	    // The next 2 authenticated requests should succeed (budget still full)
125	    mockGet.mockResolvedValue({ data: [] });
126	    const res1 = await request(freshApp).get('/api/fibaro/devices').set(AUTH);
127	    const res2 = await request(freshApp).get('/api/fibaro/devices').set(AUTH);
128	    expect(res1.status).toBe(200);
129	    expect(res2.status).toBe(200);
130	    // The 3rd authenticated request exceeds the 2-request limit
131	    const res3 = await request(freshApp).get('/api/fibaro/devices').set(AUTH);
132	    expect(res3.status).toBe(429);
133	  });
134	
